  ('dietitian-moex-08454', 'dietitian', 'dietitian-moex-098-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '根據歷年營養健康狀況調查結果顯示，台灣地區學童下列何種血液生化值有下降之趨勢？', '["血糖", "尿酸", "三酸甘油酯", "高密度脂蛋白膽固醇"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:50+00:00", "source_pdf_sha1": "3add4eefe485", "answer_pdf_sha1": "7ce9b6bd0e76", "source_family": "moex-gov-tw", "moex": {"exam_code": "098140", "c": "113", "s": "5001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公共衛生營養學", "year": "098", "exam_name": "098年第二次醫事人員、中醫師、心理師、營養師、醫師分試 、法醫師", "original_question_number": 7, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-08455', 'dietitian', 'dietitian-moex-098-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '根據「老人國民營養健康狀況變遷調查，1999-2000」的調查結果，我國老年人的最主要蛋白質食物來源 為：', '["五穀根莖類", "黃豆類及其製品", "家畜類及其製品", "魚及水產類"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:50+00:00", "source_pdf_sha1": "3add4eefe485", "answer_pdf_sha1": "7ce9b6bd0e76", "source_family": "moex-gov-tw", "moex": {"exam_code": "098140", "c": "113", "s": "5001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公共衛生營養學", "year": "098", "exam_name": "098年第二次醫事人員、中醫師、心理師、營養師、醫師分試 、法醫師", "original_question_number": 8, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-08456', 'dietitian', 'dietitian-moex-098-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '一項社區體重控制計畫報告指出，有50%參與計畫者的體重達到理想值，與預定的目標符合。此種計畫評 量稱為：', '["效果（effort）", "效益（effectiveness）", "效率（efficiency）", "效力（efficacy）"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:50+00:00", "source_pdf_sha1": "3add4eefe485", "answer_pdf_sha1": "7ce9b6bd0e76", "source_family": "moex-gov-tw", "moex": {"exam_code": "098140", "c": "113", "s": "5001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公共衛生營養學", "year": "098", "exam_name": "098年第二次醫事人員、中醫師、心理師、營養師、醫師分試 、法醫師", "original_question_number": 9, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-08457', 'dietitian', 'dietitian-moex-098-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '「老人國民營養健康狀況變遷調查，1999-2000」的結果顯示老年人的營養素攝取已經高於「國人膳食營 養素參考攝取量，DRIs」的為：', '["鐵", "鈣", "維生素E", "鎂"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:50+00:00", "source_pdf_sha1": "3add4eefe485", "answer_pdf_sha1": "7ce9b6bd0e76", "source_family": "moex-gov-tw", "moex": {"exam_code": "098140", "c": "113", "s": "5001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公共衛生營養學", "year": "098", "exam_name": "098年第二次醫事人員、中醫師、心理師、營養師、醫師分試 、法醫師", "original_question_number": 10, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-08458', 'dietitian', 'dietitian-moex-098-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '社區營養問題確定後，即需提出各種問題解決方案。若由互不認識且不同專業與經驗成員組成小組，討 論具有爭議性的方案時，下列何種方法較為適用？', '["指名小組法（nominal group process）", "焦點團體討論（focus group discussion）", "調查法（survey method）", "面談法（interview method）"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:50+00:00", "source_pdf_sha1": "3add4eefe485", "answer_pdf_sha1": "7ce9b6bd0e76", "source_family": "moex-gov-tw", "moex": {"exam_code": "098140", "c": "113", "s": "5001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公共衛生營養學", "year": "098", "exam_name": "098年第二次醫事人員、中醫師、心理師、營養師、醫師分試 、法醫師", "original_question_number": 11, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-08459', 'dietitian', 'dietitian-moex-098-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', 'SWOT 是一種在設計社區營養計畫前，用來瞭解所處環境之趨勢及其對計畫可能影響的一種分析方法， 其中之「T」代表：', '["Trend", "Threats", "Try", "Team"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:50+00:00", "source_pdf_sha1": "3add4eefe485", "answer_pdf_sha1": "7ce9b6bd0e76", "source_family": "moex-gov-tw", "moex": {"exam_code": "098140", "c": "113", "s": "5001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公共衛生營養學", "year": "098", "exam_name": "098年第二次醫事人員、中醫師、心理師、營養師、醫師分試 、法醫師", "original_question_number": 12, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-08460', 'dietitian', 'dietitian-moex-098-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '執行某項營養計畫後發現在20位接受營養照顧之高血壓病患中，有8位達正常範圍，15位改善飲食攝取 習慣。以上評估計畫成效之方式屬於下列何者？', '["Process evaluation", "Outcome evaluation", "Economic evaluation", "Cost-effect evaluation"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:50+00:00", "source_pdf_sha1": "3add4eefe485", "answer_pdf_sha1": "7ce9b6bd0e76", "source_family": "moex-gov-tw", "moex": {"exam_code": "098140", "c": "113", "s": "5001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公共衛生營養學", "year": "098", "exam_name": "098年第二次醫事人員、中醫師、心理師、營養師、醫師分試 、法醫師", "original_question_number": 13, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-08461', 'dietitian', 'dietitian-moex-098-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '依據行為改變的跨理論模式（Transtheoretical Model）觀點，如果某個案為達成體重控制目的，因此尋求 以無糖飲料取代高糖飲料。此一行為改變是屬於下列何種方法？', '["反制約（Counter conditioning）", "助人人際關係（Helping relationships）", "自我再評價（Self-revaluation）", "刺激控制（Stimulus control）"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:50+00:00", "source_pdf_sha1": "3add4eefe485", "answer_pdf_sha1": "7ce9b6bd0e76", "source_family": "moex-gov-tw", "moex": {"exam_code": "098140", "c": "113", "s": "5001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公共衛生營養學", "year": "098", "exam_name": "098年第二次醫事人員、中醫師、心理師、營養師、醫師分試 、法醫師", "original_question_number": 14, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-08462', 'dietitian', 'dietitian-moex-098-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '下列何者不是營養諮詢過程中營養師自我揭露（self-disclosure）的目的之一？', '["用來檢核諮商師對個案進步情形的瞭解", "提供開放的諮商環境", "降低諮商師與個案彼此角色差異所造成的距離", "提供一個協助個案自我表露的模式"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:50+00:00", "source_pdf_sha1": "3add4eefe485", "answer_pdf_sha1": "7ce9b6bd0e76", "source_family": "moex-gov-tw", "moex": {"exam_code": "098140", "c": "113", "s": "5001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公共衛生營養學", "year": "098", "exam_name": "098年第二次醫事人員、中醫師、心理師、營養師、醫師分試 、法醫師", "original_question_number": 15, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-08463', 'dietitian', 'dietitian-moex-098-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '改善食物供應環境來促進健康飲食行為是近年來受重視的議題，下列何者不是此類行動？', '["公共場所自動販賣機販售水果", "學校午餐供應牛奶", "業者研發低熱量烘焙製品", "政府課徵垃圾食物稅"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:50+00:00", "source_pdf_sha1": "3add4eefe485", "answer_pdf_sha1": "7ce9b6bd0e76", "source_family": "moex-gov-tw", "moex": {"exam_code": "098140", "c": "113", "s": "5001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公共衛生營養學", "year": "098", "exam_name": "098年第二次醫事人員、中醫師、心理師、營養師、醫師分試 、法醫師", "original_question_number": 16, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL)
